export async function unlinkGoogleAccount(): Promise<UserResponse> {
  const csrfToken = await ensureAccessCsrfToken()
  return authRequest<UserResponse>('/google/unlink', {
    method: 'POST',
    headers: {
      'X-CSRF-TOKEN': csrfToken,
